<template>
  <transition name="modal">
    <div
      v-if="show"
      :class="
        'flex fixed inset-0 w-full h-full z-20 items-center justify-center ' +
        'bg-gray-500 bg-opacity-60'
      "
      @click.self="close"
    >
      <!-- Modal -->
      <div class="flex flex-col rounded-xl overflow-y-hidden shadow-xl m-4 modal-content">
        <!-- Main -->
        <div class="flex flex-col flex-grow px-6 pt-4 pb-2 overflow-y-auto">
          <div class="grid grid-cols-10 my-1">
            <div class="col-span-2">レアリティ</div>
            <div
              v-for="item in [
                { value: 0, text: 'R' },
                { value: 1, text: 'SR' },
                { value: 2, text: 'SSR' },
              ]"
              :key="item.value"
            >
              <label class="cursor-pointer">
                <input
                  type="checkbox"
                  class="cursor-pointer rounded shadow-sm transition mx-1"
                  :value="item.value"
                  v-model="filterRarity"
                />
                {{ item.text }}
              </label>
            </div>
          </div>

          <div class="grid grid-cols-10 items-center my-1">
            <div class="col-span-2">得意練習</div>
            <div
              v-for="item in [
                { value: 0, text: 'スピード' },
                { value: 1, text: 'スタミナ' },
                { value: 2, text: 'パワー' },
                { value: 3, text: '根性' },
                { value: 4, text: '賢さ' },
                { value: 5, text: '友人' },
              ]"
              :key="item.value"
            >
              <label class="cursor-pointer">
                <input
                  type="checkbox"
                  class="cursor-pointer rounded shadow-sm transition mx-1"
                  :value="item.value"
                  v-model="filterCommand"
                />
                {{ item.text }}
              </label>
            </div>
            <div class="flex col-span-2 justify-center">
              <button
                class="hover:bg-gray-100 border border-gray-600 rounded-xl shadow px-4 py-1 text-sm"
                @click="resetFilter"
              >
                絞り込みをリセット
              </button>
            </div>
          </div>

          <!-- Cards -->
          <div class="flex-grow grid grid-cols-4 mt-2 overflow-y-hidden">
            <div class="col-span-3 leading-none overflow-y-auto">
              <support-card
                v-for="card in supportCardsFiltered"
                :id="card.id"
                :key="`support-card-${card.id}`"
                class="m-1"
                :class="disabledCards.includes(card.id) ? 'opacity-40' : ''"
                :rarity="card.rarity"
                :type="card.command_id"
                :width="90"
                @click="onClick(card.id)"
              />
            </div>

            <!-- Selected card -->
            <div class="py-4">
              <div v-if="selectedId !== -1" class="flex flex-col items-center">
                <support-card
                  :id="selectedId"
                  :rarity="selectedCard.rarity"
                  :type="selectedCard.command_id"
                  :diamond="+diamond"
                  :level="level"
                  :width="120"
                  :class="animationClass"
                />
                <div class="mt-4">上限解放: {{ ["無", "1", "2", "3", "完"][+diamond] }}凸</div>
                <input class="mt-1 w-36" type="range" min="0" max="4" v-model="diamond" />
              </div>
              <div v-else class="text-center">未選択</div>
            </div>
          </div>
        </div>

        <!-- Bottom area -->
        <div class="flex flex-row-reverse px-6 pb-5">
          <button
            :class="
              'inline-flex justify-center rounded-md border border-transparent shadow-sm ' +
              'ml-4 px-5 py-2 w-auto bg-green-600 text-white hover:bg-green-700 ' +
              'focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 ' +
              'disabled:opacity-40 disabled:bg-green-600 disabled:cursor-not-allowed'
            "
            :disabled="selectedId === -1"
            @click="select"
          >
            決定
          </button>
          <button
            :class="
              'inline-flex justify-center rounded-md border border-gray-300 shadow-sm ' +
              'ml-4 px-5 py-2 w-auto bg-white hover:bg-gray-50 ' +
              'focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500'
            "
            @click="close"
          >
            閉じる
          </button>
        </div>
      </div>
    </div>
  </transition>
</template>

<script lang="ts">
import { defineComponent, PropType } from "vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

type CardInfo = { detail: typeof SupportCardJson[number]; diamond: number; level: number };

export default defineComponent({
  name: "AddSupportModal",
  components: { SupportCard },

  data: function () {
    const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
    const emptyNumberArray: number[] = [];

    return {
      supportCards,
      selectedId: -1,
      diamond: "4",
      filterRarity: [...emptyNumberArray],
      filterCommand: [...emptyNumberArray],
      animationClass: "",
    };
  },

  props: {
    show: {
      type: Boolean,
      required: true,
    },
    cards: {
      type: Array as PropType<(CardInfo | null)[]>,
      required: true,
    },
    deckIndex: {
      type: Number,
      required: true,
    },
  },

  computed: {
    selectedCard: function (): typeof SupportCardJson[number] {
      return this.supportCards[this.selectedId];
    },

    disabledCards: function (): number[] {
      let result: number[] = [];
      const selectedCharaId = this.cards[this.deckIndex]?.detail.chara_id ?? -1;
      const usedCharaId = this.cards
        .filter((usedCard): usedCard is NonNullable<typeof usedCard> => {
          return usedCard != null && usedCard.detail.chara_id !== selectedCharaId;
        })
        .map((usedCard) => usedCard.detail.chara_id);

      for (const card of SupportCardJson) {
        if (usedCharaId.includes(card.chara_id)) {
          result.push(card.id);
        }
      }

      return result;
    },

    addedCards: function (): number[] {
      let result: number[] = [];
      for (const cardInfo of this.cards) {
        if (cardInfo != null) {
          result.push(cardInfo.detail.chara_id);
        }
      }
      return result;
    },

    supportCardsSorted: function (): typeof SupportCardJson {
      let cards = SupportCardJson;
      cards.sort((lhs, rhs) => {
        return (
          (rhs.rarity - lhs.rarity) * 1000000000 +
          (lhs.chara_id - rhs.chara_id) * 100000 +
          (lhs.id - rhs.id)
        );
      });
      return cards;
    },

    supportCardsFiltered: function (): typeof SupportCardJson {
      let cards = this.supportCardsSorted;
      if (this.filterRarity.length) {
        cards = cards.filter((card) => this.filterRarity.includes(card.rarity));
      }
      if (this.filterCommand.length) {
        cards = cards.filter((card) => this.filterCommand.includes(card.command_id));
      }
      return cards;
    },

    level: function (): number {
      return 20 + 5 * +this.diamond + 5 * this.selectedCard.rarity;
    },
  },

  methods: {
    close: function () {
      this.selectedId = -1;
      this.diamond = "4";
      this.$emit("update:show", false);
    },

    select: function () {
      if (this.selectedId !== -1) {
        this.$emit("select", {
          detail: this.selectedCard,
          diamond: +this.diamond,
          level: this.level,
        });
      }
      this.close();
    },

    onClick: function (id: number) {
      if (!this.disabledCards.includes(id) && this.selectedId != id) {
        this.selectedId = id;
        this.animationClass = "selected";
        setTimeout(() => (this.animationClass = "select-animation"), 10);
      }
    },

    resetFilter: function () {
      this.filterRarity = [];
      this.filterCommand = [];
    },
  },
});
</script>

