const trainingEffect = {
  speed: [
    { speed: 10, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -21 },
    { speed: 11, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -22 },
    { speed: 12, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -23 },
