    { speed: 14, stamina: 0, power: 7, guts: 0, wiz: 0, skill: 2, vital: -27 },
  ],
  stamina: [
    { speed: 0, stamina: 9, power: 0, guts: 4, wiz: 0, skill: 2, vital: -19 },
    { speed: 0, stamina: 10, power: 0, guts: 4, wiz: 0, skill: 2, vital: -20 },
    { speed: 0, stamina: 11, power: 0, guts: 4, wiz: 0, skill: 2, vital: -21 },
