    { speed: 4, stamina: 0, power: 0, guts: 0, wiz: 13, skill: 4, vital: 5 },
  ],
};

const motivation = [
  { label: "絶好調", value: 0.2 },
  { label: "好調", value: 0.1 },
  { label: "普通", value: 0 },
  { label: "不調", value: -0.1 },
  { label: "絶不調", value: -0.2 },
];

export default defineComponent({
  name: "App",
  components: { SupportCard },

  data: function () {
    const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
    const emptyNumberArray: number[] = [];

    return {
      supportCards,
      effectText,
      effectPer,
      motivation,
      selectedId: -1,
      diamond: "4",
      trainingLv: 5,
      motivationValue: 0.2,
      filterRarity: [...emptyNumberArray],
      filterCommand: [...emptyNumberArray],
      activeTab: "stats",
      animationClass: "",
    };
  },

  computed: {
    selectedCard: function (): typeof SupportCardJson[number] {
      return this.supportCards[this.selectedId];
    },

    supportCardsSorted: function (): typeof SupportCardJson {
      let cards = SupportCardJson;
      cards.sort((lhs, rhs) => {
        return (
          (rhs.rarity - lhs.rarity) * 1000000000 +
          (lhs.chara_id - rhs.chara_id) * 100000 +
          (lhs.id - rhs.id)
        );
      });
      return cards;
    },

    supportCardsFiltered: function (): typeof SupportCardJson {
      let cards = this.supportCardsSorted;
      if (this.filterRarity.length) {
        cards = cards.filter((card) => this.filterRarity.includes(card.rarity));
      }
      if (this.filterCommand.length) {
        cards = cards.filter((card) => this.filterCommand.includes(card.command_id));
      }
      return cards;
    },

    level: function (): number {
      return 20 + 5 * +this.diamond + 5 * this.selectedCard.rarity;
    },

    supportCardEffects: function (): { type: number; value: number; lv: number }[] {
      let effects: { type: number; value: number; lv: number }[] = [];

      for (const effect of this.selectedCard.effect) {
        let lo = { lv: -1, value: -1 };
        let hi = { lv: -1, value: -1 };

        for (let i = Math.floor(this.level / 5); i >= 0; --i) {
          if (effect.value[i] !== -1) {
            lo = { lv: i * 5 + +(i === 0), value: effect.value[i] };
            break;
          }
        }

        for (let i = Math.ceil(this.level / 5); i <= 10; ++i) {
          if (effect.value[i] !== -1) {
            hi = { lv: i * 5, value: effect.value[i] };
            break;
          }
        }

        if (lo.value === -1) {
          effects.push({ type: effect.type, value: -1, lv: hi.lv });
        } else if (hi.value === -1 || lo.lv === hi.lv) {
          effects.push({ type: effect.type, value: lo.value, lv: -1 });
        } else {
          const value = lo.value + ((this.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
          effects.push({ type: effect.type, value: Math.floor(value), lv: -1 });
        }
      }

      effects.sort(function (lhs, rhs) {
        if (lhs.value === -1 && rhs.value === -1) {
          return (lhs.lv - rhs.lv) * 100 + (lhs.type - rhs.type);
        } else if (lhs.value === -1) {
          return 1;
        } else if (rhs.value === -1) {
          return -1;
        } else {
          return lhs.type - rhs.type;
        }
      });

      return effects;
    },

    trainingEffect: function (): {
      text: string;
      effect: typeof trainingEffect[keyof typeof trainingEffect][number];
    } {
      type KeyType = keyof typeof trainingEffect[keyof typeof trainingEffect][number];
      const keys: KeyType[] = ["speed", "stamina", "power", "guts", "wiz"];
      const key = keys[this.selectedCard.command_id];
      const effect = { ...trainingEffect[key as keyof typeof trainingEffect][this.trainingLv - 1] };
      const text = ["スピード", "スタミナ", "パワー", "根性", "賢さ"][this.selectedCard.command_id];

      // 基礎ボーナス (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (3 <= supportEffect.type && supportEffect.type <= 7) {
            const key = keys[supportEffect.type - 3];
            if (effect[key] !== 0) {
              effect[key] += supportEffect.value;
            }
          }
        }
      }

      // 基礎ボーナス
      for (const supportEffect of this.supportCardEffects) {
        if (3 <= supportEffect.type && supportEffect.type <= 7 && supportEffect.value !== -1) {
          const key = keys[supportEffect.type - 3];
          if (effect[key] !== 0) {
            effect[key] += supportEffect.value;
          }
        }
      }

      // 友情ボーナス (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 1) {
            for (let i = 0; i < 5; ++i) {
              effect[keys[i]] *= 1.0 + supportEffect.value / 100;
            }
          }
        }
      }

      // 友情ボーナス
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 1 && supportEffect.value !== -1) {
          for (let i = 0; i < 5; ++i) {
            effect[keys[i]] *= 1.0 + supportEffect.value / 100;
          }
        }
      }

      let motivationCoef = 1.0;

      // やる気効果 (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 2) {
            motivationCoef += supportEffect.value / 100;
          }
        }
      }

      // やる気効果
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 2 && supportEffect.value !== -1) {
          motivationCoef += supportEffect.value / 100;
        }
      }

      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= 1.0 + this.motivationValue * motivationCoef;
      }

      let trainingCoef = 1.0;

      // トレーニング効果 (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 8) {
            trainingCoef += supportEffect.value / 100;
          }
        }
      }

      // トレーニング効果
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 8 && supportEffect.value !== -1) {
          trainingCoef += supportEffect.value / 100;
        }
      }

      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= trainingCoef;
      }

      // 人数補正
      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= 1.05;
      }

      // 切り捨て
      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] = Math.floor(effect[keys[i]]);
      }

      return { text, effect };
    },

    trainingRate: function (): number {
      let rate = 100;

      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 19) {
            rate *= 1.0 + supportEffect.value / 100;
          }
        }
      }

      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 19 && supportEffect.value !== -1) {
          rate *= 1.0 + supportEffect.value / 100;
        }
      }

      return rate / (rate + 450);
    },
  },

  methods: {
    onClick: function (id: number) {
      if (this.selectedId != id) {
        this.selectedId = id;
        this.animationClass = "selected";
        setTimeout(() => (this.animationClass = "select-animation"), 10);
      }
    },

    changeDiamond: function (curValue: number, oldValue: number) {
      const oldMax = 20 + 5 * this.supportCards[this.selectedId].rarity + 5 * oldValue;
      const curMax = 20 + 5 * this.supportCards[this.selectedId].rarity + 5 * curValue;
      if (curValue > oldValue) {
        if (this.level == oldMax) {
          this.level = curMax;
        }
      } else if (curValue < oldValue) {
        this.level = Math.min(this.level, curMax);
      }
    },

    resetFilter: function () {
      this.filterRarity = [];
      this.filterCommand = [];
    },
  },
});
